#include<bits/stdc++.h>
using namespace std;
int n,m;
int c[21][21];
long long f[21][21][20010];
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        memset(f,0,sizeof(f));
        scanf("%d%d",&n,&m);
        for(int i=0;i<n;i++)
        {
            for(int j=0;j<m;j++)
            {
                scanf("%d",&c[i][j]);
            }
        }
        f[0][0][0]=1;
        for(int i=0;i<n;i++)
        {
            for(int j=0;j<m;j++)
            {
                for(int k=0;k<(1<<(m+1));k++)
                {
                    int cnt=((k>>j)&1)+((k>>m)&1);
                    if(c[i][j]==0)
                    {
                        f[i][j+1][k]+=(int)(!cnt)*f[i][j][k];
                        continue;
                    }
                    if(cnt==2)
                    {
                        f[i][j+1][k^(1<<j)^(1<<m)]+=f[i][j][k];
                    }
                    else if(cnt==1)
                    {
                        f[i][j+1][k]+=f[i][j][k];
                        f[i][j+1][k^(1<<j)^(1<<m)]+=f[i][j][k];
                    }
                    else
                    {
                        f[i][j+1][k|(1<<j)|(1<<m)]+=f[i][j][k];
                    }
                }
            }
            for(int j=0;j<(1<<m);j++)
            {
                f[i+1][0][j]=f[i][m][j];
            }
        }
        printf("%lld\n",f[n][0][0]);
    }
    return 0;
}
